const body = $json;
const schema = body.soul?.responseSchema || {};
const message = String(body.message || '').trim();
const lower = message.toLowerCase();
const replyKey = String(schema.replyKey || 'reply');
const followUpQuestionKey = schema.followUpQuestionKey ? String(schema.followUpQuestionKey) : '';
const nextStepKey = schema.nextStepKey ? String(schema.nextStepKey) : '';
const summaryKey = schema.summaryKey ? String(schema.summaryKey) : '';
const userProfileKey = schema.userProfileKey ? String(schema.userProfileKey) : '';
const rootPatternKey = schema.rootPatternKey ? String(schema.rootPatternKey) : '';

let pattern = 'clarity';
if (/(stress|druck|ueberfordert|überfordert|erschöpft|erschoepft)/.test(lower)) pattern = 'stress';
else if (/(entscheidung|decide|option|wahl|choose)/.test(lower)) pattern = 'decision';
else if (/(kunde|support|bug|problem|fehler|issue)/.test(lower)) pattern = 'support';

const descriptions = {
  stress: 'pressure and overload',
  decision: 'a decision that still needs shape',
  support: 'a concrete support issue',
  clarity: 'something that needs more clarity',
};

const questionsDe = {
  stress: 'Was fuehlt sich daran gerade am engsten oder schwersten an?',
  decision: 'Zwischen welchen zwei Optionen stehst du gerade wirklich?',
  support: 'Was genau blockiert dich im Moment am staerksten?',
  clarity: 'Wenn du dein Thema in einem Satz zuspitzen muesstest, wie wuerde er lauten?',
};

const nextStepsDe = {
  stress: 'Nenne zuerst nur den einen Teil, den du heute beeinflussen kannst.',
  decision: 'Schreibe die wichtigste Abwaegung in einem kurzen Satz auf.',
  support: 'Beschreibe zuerst den letzten Schritt vor dem Fehler oder Hindernis.',
  clarity: 'Formuliere zuerst, was du dir nach diesem Gespraech konkret erhoffst.',
};

const locale = String(body.locale || body.soul?.locale || 'de');
const soulName = String(body.soul?.name || body.soul?.id || 'Assistant');
const previousSummary = Array.isArray(body.memory?.summaries) ? body.memory.summaries.at(-1) : null;
const reply = [
  `${soulName}: Ich habe dein Anliegen aufgenommen.`,
  previousSummary ? `Ich habe noch im Blick: ${previousSummary}` : null,
  `Im Moment klingt es fuer mich vor allem nach ${descriptions[pattern]}.`,
].filter(Boolean).join(' ');

const response = {
  [replyKey]: reply,
};

if (followUpQuestionKey) response[followUpQuestionKey] = questionsDe[pattern];
if (nextStepKey) response[nextStepKey] = nextStepsDe[pattern];
if (summaryKey) response[summaryKey] = `Thema: ${descriptions[pattern]}. Nachricht: ${message.slice(0, 140)}`;
if (userProfileKey) response[userProfileKey] = {
  preferred_language: locale,
  current_focus: pattern,
};
if (rootPatternKey) response[rootPatternKey] = pattern;

return [{ json: response }];
